arguments.command:
cat <<'EOF' > /tmp/test_stackalloc_nint.cs
using System;

var span = (stackalloc nint[4]);
span[0] = 10;
span[1] = 20;
span[2] = 30;
span[3] = 40;

Console.WriteLine($"Length: {span.Length}");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"span[{i}] = {span[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
EOF
dotnet-script /tmp/test_stackalloc_nint.cs 2>&1 || dotnet script /tmp/test_stackalloc_nint.cs 2>&1 || (
  mkdir -p /tmp/stackalloc_test && cd /tmp/stackalloc_test &&
  dotnet new console --force -o . -n StackAllocTest --no-restore -f net8.0 2>/dev/null &&
  cp /tmp/test_stackalloc_nint.cs Program.cs &&
  echo '<Project Sdk="Microsoft.NET.Sdk"><PropertyGroup><OutputType>Exe</OutputType><TargetFramework>net8.0</TargetFramework><AllowUnsafeBlocks>true</AllowUnsafeBlocks></PropertyGroup></Project>' > StackAllocTest.csproj &&
  dotnet run 2>&1
)

